import type { CSSProperties, ReactNode } from "react";
import styles from "./Container.module.css";

type ContainerSize = "narrow" | "base" | "wide";

type ContainerProps = {
  children: ReactNode;
  size?: ContainerSize;
  as?: "div" | "section" | "article" | "main" | "header" | "footer";
  className?: string;
  style?: CSSProperties;
};

export default function Container({
  children,
  size = "base",
  as: Tag = "div",
  className,
  style,
}: ContainerProps) {
  const cls = [styles.container, styles[size], className]
    .filter(Boolean)
    .join(" ");
  return (
    <Tag className={cls} style={style}>
      {children}
    </Tag>
  );
}

export default function StubPlaceholder() {
  return (
    <div
      style={{
        minHeight: "60vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: "var(--s-6)",
        fontFamily: "var(--font-mono)",
        color: "var(--fg)",
        textAlign: "center",
      }}
    >
      <p style={{ maxWidth: "60ch" }}>
        this page is being rebuilt in v2. see /docs/v2_audit.md for the plan.
      </p>
    </div>
  );
}

