import type { Project } from "./types";
import hvm from "@/content/projects/hivemind";
import prp from "@/content/projects/purposeless-efficiency";
import ths from "@/content/projects/theseus";

// NOTE: in a strict "no manual list" world, this would use a build-time
// glob (e.g., webpack require.context). Next.js App Router doesn't expose
// that cleanly, so we centralize imports here. Adding a new project file
// requires one line below — no other touch points.
const ALL: Project[] = [hvm, prp, ths];

export function loadProjects(): Project[] {
  return [...ALL];
}

export function getProject(slug: string): Project | undefined {
  return ALL.find((p) => p.slug === slug);
}

// TODO(michael): replace with the real preface
const preface = [
  "This book began as a refusal. The refusal was simple: to keep producing inside systems whose only consistent output was the perpetuation of themselves. The refusal was also, more uncomfortably, a confession. I was good at producing inside those systems. The confession is what made the book necessary.",
  "Purposeless Efficiency is the first of five volumes. It examines what efficiency means once it has been severed from any external purpose — once the metric is the meaning. The remaining volumes will treat what comes after the severance: the institutions that survive it, the ones that do not, and what an honest economic order might look like once we admit the mistake.",
  "Reader, I assume you have already noticed the symptoms. The book is for the reader who has stopped pretending the symptoms are accidental.",
];
export default preface;

// TODO(michael): rewrite in your voice
const thesis = {
  thesis:
    "Hivemind is strategic analytical software for operators who must reason under uncertainty.",
  mechanism:
    "It decomposes strategy questions into evaluable hypotheses, attaches weighted evidence, and aggregates probabilistic posteriors into a structured brief.",
  moat:
    "The graph of hypotheses, evidence, and counterfactuals compounds with use. The longer an operator works in Hivemind, the harder the work is to redo elsewhere.",
};
export default thesis;

